// Package gotreesitter implements a pure Go
// tree-sitter runtime.
package gotreesitter

// Symbol is a grammar symbol ID
// (terminal or nonterminal).
type Symbol uint16

// StateID is a parser state index.
type StateID uint32

// FieldID is a named field index.
type FieldID uint16

// ParseActionType identifies the kind
// of parse action.
type ParseActionType uint8

const (
	ParseActionShift  ParseActionType = iota
	ParseActionReduce
	ParseActionAccept
	ParseActionRecover
)

// Lexer tokenizes source text using a
// table-driven DFA.
type Lexer struct {
	states     []LexState
	asciiTable [][128]int32
	source     []byte
	pos        int
	row        uint32
	col        uint32
}

func NewLexer(
	states []LexState, source []byte,
) *Lexer {
	return &Lexer{
		states: states,
		source: source,
	}
}

// Next lexes the next token starting from
// the given lex state index. It skips
// whitespace tokens automatically.
func (l *Lexer) Next(startState uint16) Token {
	for {
		if l.pos >= len(l.source) {
			return Token{
				StartByte: uint32(l.pos),
				EndByte:   uint32(l.pos),
			}
		}

// NewParser creates a new Parser for
// the given language.
func NewParser(lang *Language) *Parser {
	p := &Parser{language: lang}
	if lang != nil {
		p.denseLimit = len(lang.ParseTable)
		p.smallBase = int(lang.LargeStateCount)
		if len(lang.SmallParseTableMap) > 0 {
			p.smallLookup =
				buildSmallLookup(lang)
			p.smallTokenLookup =
				buildSmallTokenLookup(lang)
		}
		p.reduceAliasSeq =
			buildReduceAliasSequences(lang)
		p.singleTokenWrapperSymbol =
			buildSingleTokenWrapperSymbols(lang)
		p.reduceHasFields =
			buildReduceFieldPresence(lang)
		p.recoverByState,
			p.hasRecoverState,
			p.hasRecoverSymbol =
			buildRecoverActionsByState(lang)
		p.rootSymbol, p.hasRootSymbol =
			p.inferRootSymbol()
		p.maxConflictWidth =
			computeMaxConflictWidth(lang)
	}
	return p
}

func (p *Parser) Parse(
	source []byte,
) (*Tree, error) {
	if err := p.checkLanguageCompatible();
		err != nil {
		return nil, err
	}
	if err := p.checkDFALexer();
		err != nil {
		return nil, err
	}
	lexer := NewLexer(
		p.language.LexStates, source,
	)
	ts := acquireDFATokenSource(
		lexer, p.language,
		p.lookupActionIndex,
		p.hasKeywordState,
	)
	tree := p.parseInternal(
		source, p.wrapIncludedRanges(ts),
		nil, nil, arenaClassFull,
		nil, initialMaxStacks, 0, 0, false,
	)
	normalizeReturnedTree(
		rootOrNil(tree), source, p.language,
	)
	return tree, nil
}

func NewQuery(
	source string, lang *Language,
) (*Query, error) {
	p := &queryParser{
		input: source,
		lang:  lang,
		q: &Query{
			captures: []string{},
		},
	}
	if err := p.parse(); err != nil {
		return nil, err
	}
	p.q.buildAlternationIndices()
	p.q.buildRootPatternIndex()
	return p.q, nil
}

// Exec creates a streaming cursor over
// matches rooted at node.
func (q *Query) Exec(
	node *Node, lang *Language,
	source []byte,
) *QueryCursor {
	c := &QueryCursor{
		query:  q,
		lang:   lang,
		source: source,
	}
	if node != nil {
		c.worklist = make(
			[]queryCursorWorkItem, 1, 32,
		)
		c.worklist[0] = queryCursorWorkItem{
			node: node, depth: 0,
		}
	}
	return c
}

package gotreesitter

// TreeCursor provides stateful, O(1) tree
// navigation. It maintains a stack of
// (node, childIndex) frames enabling
// efficient parent, child, and sibling
// movement without scanning.
type TreeCursor struct {
	stack []cursorFrame
	tree  *Tree
}

func NewTreeCursor(
	node *Node, tree *Tree,
) *TreeCursor {
	return &TreeCursor{
		stack: []cursorFrame{
			{node: node, childIndex: -1},
		},
		tree: tree,
	}
}

// GotoFirstChild moves to the first child.
func (c *TreeCursor) GotoFirstChild() bool {
	node := c.CurrentNode()
	if node == nil ||
		len(node.children) == 0 {
		return false
	}
	c.stack = append(c.stack,
		cursorFrame{
			node:       node.children[0],
			childIndex: 0,
		},
	)
	return true
}
